"""Authentication & authorization endpoints.

Three routers are exported:
- `router`        - public/self-service auth under /auth (+ invitation accept)
- `system_router` - the hidden admin bootstrap under /system
- `admin_router`  - admin-only management under /admin

Authorization for protected routes is enforced via the dependencies in
app/dependencies.py, which re-check role/status against the database.
"""
from __future__ import annotations

import uuid
from datetime import datetime, timedelta, timezone

from fastapi import APIRouter, Depends, HTTPException, Request, Response, status
from sqlalchemy import select, text
from sqlalchemy.orm import Session

from app.auth_service import (
    RefreshError,
    clear_refresh_cookie,
    count_active_admins,
    issue_refresh_token,
    revoke_all_for_user,
    revoke_refresh_token,
    rotate_refresh_token,
    set_refresh_cookie,
    write_audit,
)
from app.config import get_settings
from app.db import get_db
from app.dependencies import CurrentUser, get_current_user, invalidate_user_cache, require_role
from app.email import (
    send_invitation_email,
    send_password_reset_email,
    send_verification_email,
)
from app.enums import UserRole, UserStatus, VerificationPurpose
from app.models import BusinessUnit, Invitation, Organization, User, VerificationToken
from app.ratelimit import limiter
from app.schemas import (
    ApproveUserRequest,
    InvitationAcceptRequest,
    InvitationCreateRequest,
    InvitationOut,
    LoginRequest,
    MessageResponse,
    PasswordResetConfirm,
    PasswordResetRequest,
    RoleChangeRequest,
    SignupRequest,
    TokenResponse,
    UserOut,
    VerifyEmailRequest,
)
from app.security import (
    create_access_token,
    generate_opaque_token,
    hash_password,
    hash_token,
    verify_password,
)

settings = get_settings()

router = APIRouter(prefix="/auth", tags=["auth"])
system_router = APIRouter(prefix="/system", tags=["auth"])
admin_router = APIRouter(prefix="/admin", tags=["admin"])

# Stable key for the Postgres advisory lock guarding admin bootstrap.
_BOOTSTRAP_LOCK_KEY = 918273645


def _now() -> datetime:
    return datetime.now(timezone.utc)


def _bootstrap_org(db: Session) -> Organization:
    org = db.scalar(select(Organization).order_by(Organization.created_at))
    if org is None:
        raise HTTPException(
            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
            detail="No organization is configured",
        )
    return org


def _get_org_user(db: Session, user_id: uuid.UUID, organization_id: uuid.UUID) -> User:
    user = db.get(User, user_id)
    if user is None or user.organization_id != organization_id:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="User not found")
    return user


def _validate_business_unit(
    db: Session, business_unit_id: uuid.UUID | None, organization_id: uuid.UUID
) -> None:
    if business_unit_id is None:
        return
    bu = db.get(BusinessUnit, business_unit_id)
    if bu is None or bu.organization_id != organization_id:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid business unit"
        )


def _issue_session(db: Session, response: Response, user: User) -> TokenResponse:
    """Mint an access token and set a fresh refresh cookie for `user`."""
    raw_refresh = issue_refresh_token(db, user)
    set_refresh_cookie(response, raw_refresh)
    return TokenResponse(access_token=create_access_token(user))


# --- Self-service auth -----------------------------------------------------


@router.post("/signup", response_model=MessageResponse, status_code=status.HTTP_201_CREATED)
@limiter.limit("5/minute")
async def signup(
    request: Request, payload: SignupRequest, db: Session = Depends(get_db)
) -> MessageResponse:
    email = payload.email.lower()
    if db.scalar(select(User).where(User.email == email)) is not None:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT, detail="An account with this email already exists"
        )

    org = _bootstrap_org(db)
    user = User(
        organization_id=org.id,
        email=email,
        full_name=payload.full_name,
        password_hash=hash_password(payload.password),
        role=None,
        status=UserStatus.PENDING_APPROVAL,
    )
    db.add(user)
    db.flush()

    raw_token = generate_opaque_token()
    db.add(
        VerificationToken(
            user_id=user.id,
            purpose=VerificationPurpose.EMAIL_VERIFY,
            token_hash=hash_token(raw_token),
            expires_at=_now() + timedelta(hours=settings.email_verify_ttl_hours),
        )
    )
    write_audit(db, "signup", actor_user_id=user.id, actor=email)
    db.commit()

    await send_verification_email(email, raw_token)
    return MessageResponse(
        detail="Account created. Check your email to verify it, then await admin approval."
    )


@system_router.post(
    "/admin-signup", response_model=TokenResponse | MessageResponse, status_code=status.HTTP_201_CREATED
)
@limiter.limit("5/minute")
async def admin_signup(
    request: Request, payload: SignupRequest, response: Response, db: Session = Depends(get_db)
):
    """Hidden bootstrap route. The very first admin (when none exist) is created
    pre-approved; subsequent requests enter the admin approval queue."""
    email = payload.email.lower()
    if db.scalar(select(User).where(User.email == email)) is not None:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT, detail="An account with this email already exists"
        )

    org = _bootstrap_org(db)

    # Serialize the count-then-create so exactly one bootstrap admin can win.
    db.execute(text("SELECT pg_advisory_xact_lock(:k)"), {"k": _BOOTSTRAP_LOCK_KEY})
    admin_count = count_active_admins(db, org.id)

    if admin_count == 0:
        user = User(
            organization_id=org.id,
            email=email,
            full_name=payload.full_name,
            password_hash=hash_password(payload.password),
            role=UserRole.ADMIN,
            status=UserStatus.APPROVED,
            email_verified_at=_now(),
            approved_at=_now(),
        )
        db.add(user)
        db.flush()
        write_audit(db, "admin_bootstrap", actor_user_id=user.id, actor=email)
        token = _issue_session(db, response, user)
        db.commit()
        return token

    user = User(
        organization_id=org.id,
        email=email,
        full_name=payload.full_name,
        password_hash=hash_password(payload.password),
        role=None,
        requested_role=UserRole.ADMIN,
        status=UserStatus.PENDING_APPROVAL,
    )
    db.add(user)
    db.flush()
    raw_token = generate_opaque_token()
    db.add(
        VerificationToken(
            user_id=user.id,
            purpose=VerificationPurpose.EMAIL_VERIFY,
            token_hash=hash_token(raw_token),
            expires_at=_now() + timedelta(hours=settings.email_verify_ttl_hours),
        )
    )
    write_audit(db, "admin_signup_requested", actor_user_id=user.id, actor=email)
    db.commit()

    await send_verification_email(email, raw_token)
    return MessageResponse(detail="Admin request submitted. An existing admin must approve it.")


@router.post("/login", response_model=TokenResponse)
@limiter.limit("10/minute")
def login(
    request: Request, payload: LoginRequest, response: Response, db: Session = Depends(get_db)
) -> TokenResponse:
    email = payload.email.lower()
    user = db.scalar(select(User).where(User.email == email))
    # Verify against a hash even when the user is missing to reduce timing/enumeration signal.
    valid = user is not None and verify_password(payload.password, user.password_hash)
    if not valid or user is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED, detail="Invalid email or password"
        )
    if user.email_verified_at is None:
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN, detail="Please verify your email first"
        )
    if user.status != UserStatus.APPROVED:
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN, detail="Your account is not active yet"
        )

    write_audit(db, "login", actor_user_id=user.id, actor=user.email)
    token = _issue_session(db, response, user)
    db.commit()
    return token


@router.post("/refresh", response_model=TokenResponse)
@limiter.limit("30/minute")
def refresh(request: Request, response: Response, db: Session = Depends(get_db)) -> TokenResponse:
    raw = request.cookies.get(settings.refresh_cookie_name)
    if not raw:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Missing refresh token")
    try:
        user, new_raw = rotate_refresh_token(db, raw)
    except RefreshError as exc:
        db.commit()  # persist any family revocation done during reuse detection
        clear_refresh_cookie(response)
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail=str(exc))

    set_refresh_cookie(response, new_raw)
    access = create_access_token(user)
    db.commit()
    return TokenResponse(access_token=access)


@router.post("/logout", response_model=MessageResponse)
@limiter.limit("30/minute")
def logout(request: Request, response: Response, db: Session = Depends(get_db)) -> MessageResponse:
    raw = request.cookies.get(settings.refresh_cookie_name)
    if raw:
        revoke_refresh_token(db, raw)
        write_audit(db, "logout")
        db.commit()
    clear_refresh_cookie(response)
    return MessageResponse(detail="Logged out")


@router.post("/verify-email", response_model=MessageResponse)
@limiter.limit("10/minute")
def verify_email(
    request: Request, payload: VerifyEmailRequest, db: Session = Depends(get_db)
) -> MessageResponse:
    record = _consume_verification(db, payload.token, VerificationPurpose.EMAIL_VERIFY)
    user = db.get(User, record.user_id)
    if user is not None and user.email_verified_at is None:
        user.email_verified_at = _now()
        write_audit(db, "email_verified", actor_user_id=user.id, actor=user.email)
    db.commit()
    return MessageResponse(detail="Email verified")


@router.post("/password-reset/request", response_model=MessageResponse)
@limiter.limit("5/minute")
async def password_reset_request(
    request: Request, payload: PasswordResetRequest, db: Session = Depends(get_db)
) -> MessageResponse:
    email = payload.email.lower()
    user = db.scalar(select(User).where(User.email == email))
    if user is not None:
        raw_token = generate_opaque_token()
        db.add(
            VerificationToken(
                user_id=user.id,
                purpose=VerificationPurpose.PASSWORD_RESET,
                token_hash=hash_token(raw_token),
                expires_at=_now() + timedelta(hours=settings.password_reset_ttl_hours),
            )
        )
        write_audit(db, "password_reset_requested", actor_user_id=user.id, actor=email)
        db.commit()
        await send_password_reset_email(email, raw_token)
    # Always 200 to avoid revealing whether the email is registered.
    return MessageResponse(detail="If that account exists, a reset link has been sent.")


@router.post("/password-reset/confirm", response_model=MessageResponse)
@limiter.limit("5/minute")
def password_reset_confirm(
    request: Request, payload: PasswordResetConfirm, db: Session = Depends(get_db)
) -> MessageResponse:
    record = _consume_verification(db, payload.token, VerificationPurpose.PASSWORD_RESET)
    user = db.get(User, record.user_id)
    if user is None:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid token")
    user.password_hash = hash_password(payload.new_password)
    revoke_all_for_user(db, user.id)
    write_audit(db, "password_reset_confirmed", actor_user_id=user.id, actor=user.email)
    db.commit()
    return MessageResponse(detail="Password updated. Please log in again.")


@router.get("/me", response_model=UserOut)
def me(user: CurrentUser = Depends(get_current_user), db: Session = Depends(get_db)) -> UserOut:
    db_user = db.get(User, user.id)
    return UserOut.model_validate(db_user)


@router.post("/invitations/accept", response_model=TokenResponse, status_code=status.HTTP_201_CREATED)
@limiter.limit("10/minute")
def accept_invitation(
    request: Request,
    payload: InvitationAcceptRequest,
    response: Response,
    db: Session = Depends(get_db),
) -> TokenResponse:
    invite = db.scalar(
        select(Invitation).where(Invitation.token_hash == hash_token(payload.token))
    )
    if invite is None or invite.used_at is not None or invite.expires_at <= _now():
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid or expired invitation"
        )
    if db.scalar(select(User).where(User.email == invite.email)) is not None:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT, detail="An account with this email already exists"
        )

    # Invited users bypass the approval queue and are active immediately.
    user = User(
        organization_id=invite.organization_id,
        business_unit_id=invite.business_unit_id,
        email=invite.email,
        full_name=payload.full_name,
        password_hash=hash_password(payload.password),
        role=invite.role,
        status=UserStatus.APPROVED,
        email_verified_at=_now(),
        approved_by=invite.invited_by,
        approved_at=_now(),
    )
    db.add(user)
    invite.used_at = _now()
    db.flush()
    write_audit(db, "invite_redeemed", actor_user_id=user.id, actor=user.email)
    token = _issue_session(db, response, user)
    db.commit()
    return token


def _consume_verification(
    db: Session, raw_token: str, purpose: VerificationPurpose
) -> VerificationToken:
    record = db.scalar(
        select(VerificationToken).where(
            VerificationToken.token_hash == hash_token(raw_token),
            VerificationToken.purpose == purpose,
        )
    )
    if record is None or record.used_at is not None or record.expires_at <= _now():
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid or expired token"
        )
    record.used_at = _now()
    return record


# --- Admin management ------------------------------------------------------

_admin_only = require_role([UserRole.ADMIN])


@admin_router.get("/approvals", response_model=list[UserOut])
def list_pending(
    admin: CurrentUser = Depends(_admin_only), db: Session = Depends(get_db)
) -> list[UserOut]:
    rows = db.scalars(
        select(User).where(
            User.organization_id == admin.organization_id,
            User.status == UserStatus.PENDING_APPROVAL,
        )
    ).all()
    return [UserOut.model_validate(r) for r in rows]


@admin_router.post("/approvals/{user_id}/approve", response_model=UserOut)
def approve_user(
    user_id: uuid.UUID,
    payload: ApproveUserRequest,
    admin: CurrentUser = Depends(_admin_only),
    db: Session = Depends(get_db),
) -> UserOut:
    target = _get_org_user(db, user_id, admin.organization_id)
    if target.status != UserStatus.PENDING_APPROVAL:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT, detail="User is not awaiting approval"
        )
    _validate_business_unit(db, payload.business_unit_id, admin.organization_id)

    target.role = payload.role
    target.business_unit_id = payload.business_unit_id
    target.status = UserStatus.APPROVED
    target.approved_by = admin.id
    target.approved_at = _now()
    write_audit(
        db,
        "user_approved",
        actor_user_id=admin.id,
        actor=admin.email,
        detail={"target": str(target.id), "role": payload.role.value},
    )
    db.commit()
    invalidate_user_cache(target.id)
    return UserOut.model_validate(target)


@admin_router.post("/approvals/{user_id}/reject", response_model=UserOut)
def reject_user(
    user_id: uuid.UUID,
    admin: CurrentUser = Depends(_admin_only),
    db: Session = Depends(get_db),
) -> UserOut:
    target = _get_org_user(db, user_id, admin.organization_id)
    if target.status != UserStatus.PENDING_APPROVAL:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT, detail="User is not awaiting approval"
        )
    target.status = UserStatus.REJECTED
    write_audit(
        db, "user_rejected", actor_user_id=admin.id, actor=admin.email,
        detail={"target": str(target.id)},
    )
    db.commit()
    invalidate_user_cache(target.id)
    return UserOut.model_validate(target)


@admin_router.get("/users", response_model=list[UserOut])
def list_users(
    admin: CurrentUser = Depends(_admin_only), db: Session = Depends(get_db)
) -> list[UserOut]:
    rows = db.scalars(
        select(User).where(User.organization_id == admin.organization_id)
    ).all()
    return [UserOut.model_validate(r) for r in rows]


@admin_router.post("/users/{user_id}/role", response_model=UserOut)
def change_role(
    user_id: uuid.UUID,
    payload: RoleChangeRequest,
    admin: CurrentUser = Depends(_admin_only),
    db: Session = Depends(get_db),
) -> UserOut:
    if user_id == admin.id:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST, detail="You cannot change your own role"
        )
    target = _get_org_user(db, user_id, admin.organization_id)
    _validate_business_unit(db, payload.business_unit_id, admin.organization_id)

    # Guard the last remaining admin from being demoted.
    if (
        target.role == UserRole.ADMIN
        and payload.role != UserRole.ADMIN
        and count_active_admins(db, admin.organization_id, exclude_user_id=target.id) == 0
    ):
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Cannot demote the last remaining admin",
        )

    target.role = payload.role
    target.business_unit_id = payload.business_unit_id
    revoke_all_for_user(db, target.id)
    write_audit(
        db, "role_changed", actor_user_id=admin.id, actor=admin.email,
        detail={"target": str(target.id), "role": payload.role.value},
    )
    db.commit()
    invalidate_user_cache(target.id)
    return UserOut.model_validate(target)


@admin_router.post("/users/{user_id}/disable", response_model=UserOut)
def disable_user(
    user_id: uuid.UUID,
    admin: CurrentUser = Depends(_admin_only),
    db: Session = Depends(get_db),
) -> UserOut:
    if user_id == admin.id:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST, detail="You cannot disable your own account"
        )
    target = _get_org_user(db, user_id, admin.organization_id)
    if (
        target.role == UserRole.ADMIN
        and count_active_admins(db, admin.organization_id, exclude_user_id=target.id) == 0
    ):
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Cannot disable the last remaining admin",
        )

    target.status = UserStatus.DISABLED
    revoke_all_for_user(db, target.id)
    write_audit(
        db, "user_disabled", actor_user_id=admin.id, actor=admin.email,
        detail={"target": str(target.id)},
    )
    db.commit()
    invalidate_user_cache(target.id)
    return UserOut.model_validate(target)


@admin_router.get("/invitations", response_model=list[InvitationOut])
def list_invitations(
    admin: CurrentUser = Depends(_admin_only), db: Session = Depends(get_db)
) -> list[InvitationOut]:
    rows = db.scalars(
        select(Invitation).where(Invitation.organization_id == admin.organization_id)
    ).all()
    return [InvitationOut.model_validate(r) for r in rows]


@admin_router.post("/invitations", response_model=InvitationOut, status_code=status.HTTP_201_CREATED)
async def create_invitation(
    payload: InvitationCreateRequest,
    admin: CurrentUser = Depends(_admin_only),
    db: Session = Depends(get_db),
) -> InvitationOut:
    email = payload.email.lower()
    if db.scalar(select(User).where(User.email == email)) is not None:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT,
            detail="A user with this email already exists",
        )
    _validate_business_unit(db, payload.business_unit_id, admin.organization_id)

    # Dedup: invalidate any still-active invite for the same email before issuing.
    existing = db.scalars(
        select(Invitation).where(
            Invitation.organization_id == admin.organization_id,
            Invitation.email == email,
            Invitation.used_at.is_(None),
            Invitation.expires_at > _now(),
        )
    ).all()
    for old in existing:
        old.used_at = _now()

    raw_token = generate_opaque_token()
    invite = Invitation(
        organization_id=admin.organization_id,
        email=email,
        role=payload.role,
        business_unit_id=payload.business_unit_id,
        token_hash=hash_token(raw_token),
        invited_by=admin.id,
        expires_at=_now() + timedelta(hours=settings.invitation_ttl_hours),
    )
    db.add(invite)
    db.flush()
    write_audit(
        db, "invite_created", actor_user_id=admin.id, actor=admin.email,
        detail={"email": email, "role": payload.role.value},
    )
    db.commit()

    await send_invitation_email(email, raw_token, payload.role.value)
    return InvitationOut.model_validate(invite)

