/**
 * Access token lives in memory only (never localStorage), so it disappears on
 * tab close and cannot be read by injected scripts the way storage can. The
 * refresh token lives in an HttpOnly cookie and is used to mint a new access
 * token on page load via silent refresh.
 */
let accessToken: string | null = null;

export function getAccessToken(): string | null {
  return accessToken;
