      <h1 className="text-2xl font-semibold text-slate-900">Administration</h1>
      <ApprovalsSection />
      <InvitationsSection />
      <UsersSection />
    </div>
  );
}

function SectionCard({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <section className="rounded-lg border border-slate-200 bg-white p-6">
      <h2 className="text-lg font-semibold text-slate-900">{title}</h2>
      <div className="mt-4">{children}</div>
    </section>
  );
}

function ApprovalsSection() {
  const qc = useQueryClient();
  const query = useQuery({ queryKey: ["pending-approvals"], queryFn: listPendingApprovals });
  const [roleById, setRoleById] = useState<Record<string, UserRole>>({});

  const approve = useMutation({
    mutationFn: ({ id, role }: { id: string; role: UserRole }) => approveUser(id, role),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["pending-approvals"] });
      qc.invalidateQueries({ queryKey: ["users"] });
    },
  });
  const reject = useMutation({
    mutationFn: (id: string) => rejectUser(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["pending-approvals"] }),
  });

  return (
    <SectionCard title="Pending approvals">
      {query.isLoading ? (
        <p className="text-sm text-slate-500">Loading…</p>
      ) : query.data && query.data.length > 0 ? (
        <ul className="divide-y divide-slate-100">
          {query.data.map((u) => (
            <li key={u.id} className="flex flex-wrap items-center justify-between gap-3 py-3">
              <div>
                <p className="font-medium text-slate-900">{u.full_name}</p>
                <p className="text-sm text-slate-500">
                  {u.email}
                  {u.requested_role ? ` · requested ${u.requested_role}` : ""}
                </p>
              </div>
              <div className="flex items-center gap-2">
                <select
                  value={roleById[u.id] ?? "LEGAL_USER"}
                  onChange={(e) => setRoleById({ ...roleById, [u.id]: e.target.value as UserRole })}
                  className="rounded-md border border-slate-300 px-2 py-1.5 text-sm"
                >
                  {ROLES.map((r) => (
                    <option key={r} value={r}>
                      {r}
                    </option>
                  ))}
                </select>
                <button
                  type="button"
                  onClick={() => approve.mutate({ id: u.id, role: roleById[u.id] ?? "LEGAL_USER" })}
                  className="rounded-md bg-indigo-600 px-3 py-1.5 text-sm font-medium text-white hover:bg-indigo-700"
                >
                  Approve
                </button>
                <button
                  type="button"
                  onClick={() => reject.mutate(u.id)}
                  className="rounded-md border border-slate-300 px-3 py-1.5 text-sm font-medium text-slate-700 hover:bg-slate-100"
                >
                  Reject
                </button>
              </div>
            </li>
          ))}
        </ul>
      ) : (
        <p className="text-sm text-slate-500">No pending requests.</p>
      )}
    </SectionCard>
  );
}

function InvitationsSection() {
  const qc = useQueryClient();
  const query = useQuery({ queryKey: ["invitations"], queryFn: listInvitations });
  const [email, setEmail] = useState("");
  const [role, setRole] = useState<UserRole>("BU_USER");
  const [error, setError] = useState<string | null>(null);

  const invite = useMutation({
    mutationFn: () => createInvitation(email, role),
    onSuccess: () => {
      setEmail("");
      setError(null);
      qc.invalidateQueries({ queryKey: ["invitations"] });
    },
    onError: (err) => setError(extractError(err)),
  });

  return (
    <SectionCard title="Invitations">
      <form
        onSubmit={(e) => {
          e.preventDefault();
          invite.mutate();
        }}
        className="flex flex-wrap items-end gap-3"
      >
        <label className="flex-1">
          <span className="mb-1 block text-sm font-medium text-slate-700">Email</span>
          <input
            type="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full rounded-md border border-slate-300 px-3 py-2 text-sm"
          />
        </label>
        <label>
          <span className="mb-1 block text-sm font-medium text-slate-700">Role</span>
          <select
            value={role}
            onChange={(e) => setRole(e.target.value as UserRole)}
            className="rounded-md border border-slate-300 px-2 py-2 text-sm"
          >
            {ROLES.map((r) => (
              <option key={r} value={r}>
                {r}
              </option>
            ))}
          </select>
        </label>
        <button
          type="submit"
          disabled={invite.isPending}
          className="rounded-md bg-indigo-600 px-4 py-2 text-sm font-medium text-white hover:bg-indigo-700 disabled:opacity-50"
        >
          Send invite
        </button>
      </form>
      {error && <p className="mt-2 text-sm text-red-600">{error}</p>}

      <div className="mt-4">
        {query.data && query.data.length > 0 ? (
          <ul className="divide-y divide-slate-100 text-sm">
            {query.data.map((inv) => (
              <li key={inv.id} className="flex justify-between py-2">
                <span className="text-slate-900">{inv.email}</span>
                <span className="text-slate-500">
                  {inv.role} · {inv.used_at ? "used" : `expires ${new Date(inv.expires_at).toLocaleDateString()}`}
                </span>
              </li>
            ))}
          </ul>
        ) : (
          <p className="text-sm text-slate-500">No invitations yet.</p>
        )}
      </div>
    </SectionCard>
  );
}

function UsersSection() {
  const qc = useQueryClient();
  const query = useQuery({ queryKey: ["users"], queryFn: listUsers });

  const changeRole = useMutation({
    mutationFn: ({ id, role }: { id: string; role: UserRole }) => changeUserRole(id, role),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["users"] }),
  });
  const disable = useMutation({
    mutationFn: (id: string) => disableUser(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["users"] }),
  });

  return (
    <SectionCard title="Users">
      {query.isLoading ? (
        <p className="text-sm text-slate-500">Loading…</p>
      ) : query.data && query.data.length > 0 ? (
        <table className="min-w-full divide-y divide-slate-200 text-sm">
          <thead className="text-left text-xs font-medium uppercase tracking-wide text-slate-500">
            <tr>
              <th className="py-2">Name</th>
              <th className="py-2">Email</th>
              <th className="py-2">Status</th>
              <th className="py-2">Role</th>
              <th className="py-2 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {query.data.map((u) => (
              <tr key={u.id}>
                <td className="py-2 font-medium text-slate-900">{u.full_name}</td>
                <td className="py-2 text-slate-600">{u.email}</td>
                <td className="py-2 text-slate-600">{u.status}</td>
                <td className="py-2">
                  <select
                    value={u.role ?? ""}
                    disabled={u.status !== "APPROVED"}
                    onChange={(e) => changeRole.mutate({ id: u.id, role: e.target.value as UserRole })}
                    className="rounded-md border border-slate-300 px-2 py-1 text-sm disabled:opacity-50"
                  >
                    {u.role == null && <option value="">—</option>}
                    {ROLES.map((r) => (
                      <option key={r} value={r}>
                        {r}
                      </option>
                    ))}
                  </select>
                </td>
                <td className="py-2 text-right">
                  {u.status !== "DISABLED" && (
                    <button
                      type="button"
                      onClick={() => disable.mutate(u.id)}
                      className="rounded-md border border-slate-300 px-3 py-1 text-xs font-medium text-red-600 hover:bg-red-50"
                    >
                      Disable
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      ) : (
        <p className="text-sm text-slate-500">No users.</p>
      )}
    </SectionCard>
  );
}

