import { Route, Routes } from "react-router-dom";

import { NavBar } from "./components/NavBar";
import { ProtectedRoute } from "./auth/ProtectedRoute";
import { AcceptInvitePage } from "./pages/AcceptInvitePage";
import { AdminPage } from "./pages/AdminPage";
import { AdminSignupPage } from "./pages/AdminSignupPage";
import { ForgotPasswordPage } from "./pages/ForgotPasswordPage";
import { LoginPage } from "./pages/LoginPage";
import { RepositoryPage } from "./pages/RepositoryPage";
import { ResetPasswordPage } from "./pages/ResetPasswordPage";
import { SignupPage } from "./pages/SignupPage";
import { UploadPage } from "./pages/UploadPage";
import { VerifyEmailPage } from "./pages/VerifyEmailPage";

export default function App() {
  return (
    <div className="min-h-screen bg-slate-50 text-slate-900">
      <NavBar />
      <main className="mx-auto max-w-6xl px-6 py-8">
        <Routes>
          {/* Public auth routes */}
          <Route path="/login" element={<LoginPage />} />
          <Route path="/signup" element={<SignupPage />} />
          <Route path="/forgot-password" element={<ForgotPasswordPage />} />
          <Route path="/reset-password" element={<ResetPasswordPage />} />
          <Route path="/verify-email" element={<VerifyEmailPage />} />
          <Route path="/accept-invite" element={<AcceptInvitePage />} />
          <Route path="/system/admin-signup" element={<AdminSignupPage />} />

          {/* Authenticated routes */}
          <Route
            path="/"
            element={
              <ProtectedRoute>
                <RepositoryPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/upload"
            element={
              <ProtectedRoute>
                <UploadPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/admin"
            element={
              <ProtectedRoute roles={["ADMIN"]}>
                <AdminPage />
              </ProtectedRoute>
            }
          />

          <Route
            path="*"
            element={
              <ProtectedRoute>
                <RepositoryPage />
              </ProtectedRoute>
            }
          />
        </Routes>
      </main>
    </div>
  );
}

import { NavLink, useNavigate } from "react-router-dom";

import { useAuth } from "../auth/AuthContext";

const LINK_BASE =
  "rounded-md px-3 py-2 text-sm font-medium transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500";

export function NavBar() {
  const { user, logout, hasRole } = useAuth();
  const navigate = useNavigate();

  async function handleLogout() {
    await logout();
    navigate("/login", { replace: true });
  }

  return (
    <header className="border-b border-slate-200 bg-white">
      <nav
        className="mx-auto flex max-w-6xl items-center justify-between px-6 py-4"
        aria-label="Primary"
      >
        <span className="text-lg font-semibold text-slate-900">Contract Intelligence</span>

        {user && (
          <div className="flex items-center gap-1">
            <NavLink to="/" end className={({ isActive }) => navClass(isActive)}>
              Repository
            </NavLink>
            <NavLink to="/upload" className={({ isActive }) => navClass(isActive)}>
              Upload
            </NavLink>
            {hasRole("ADMIN") && (
              <NavLink to="/admin" className={({ isActive }) => navClass(isActive)}>
                Admin
              </NavLink>
            )}
            <span className="ml-3 text-sm text-slate-500">
              {user.full_name} · {user.role}
            </span>
            <button
              type="button"
              onClick={handleLogout}
              className="ml-2 rounded-md border border-slate-300 px-3 py-1.5 text-sm font-medium text-slate-700 hover:bg-slate-100"
            >
              Sign out
            </button>
          </div>
        )}
      </nav>
    </header>
  );
}

function navClass(isActive: boolean): string {
  const active = isActive ? "bg-indigo-50 text-indigo-700" : "text-slate-600 hover:bg-slate-100";
  return `${LINK_BASE} ${active}`;
}
